/**
 * mwa-inject.js  —  @solana-mobile/wallet-standard-mobile@0.4.4
 * ─────────────────────────────────────────────────────────────────────────────
 * On-the-fly MWA Standard Wallet Injector — INLINE BUNDLE (no server needed)
 *
 * USAGE — Chrome DevTools Console (USB remote debugging):
 *   1. Connect Android via USB → enable USB debugging
 *   2. Desktop Chrome → chrome://inspect → find tab → click "inspect"
 *   3. Paste this entire file into the Console tab → Enter
 *
 * HOW IT WORKS (client-side, no server/ngrok required):
 *   The @solana-mobile/wallet-standard-mobile@0.4.4 bundle is embedded as
 *   base64 below. At runtime it is decoded → Blob → object URL → dynamic
 *   import(). No network requests, no CSP issues, no mixed content.
 *
 * RESULT stored at window.__mwa for post-injection inspection.
 * ─────────────────────────────────────────────────────────────────────────────
 */

(async function MWAInjector() {

  // ── Config ─────────────────────────────────────────────────────────────────
  const VERSION = '0.4.4';

  // ── Logging ────────────────────────────────────────────────────────────────
  const T = '%c[MWA-INJECT]';
  const S = {
    info: 'color:#9945FF;font-weight:bold',
    ok:   'color:#14F195;font-weight:bold',
    warn: 'color:#FFB800;font-weight:bold',
    err:  'color:#FF3B3B;font-weight:bold',
  };
  const log  = (m, ...a) => console.log(T+' '+m,  S.info, ...a);
  const ok   = (m, ...a) => console.log(T+' ✅ '+m, S.ok,   ...a);
  const warn = (m, ...a) => console.warn(T+' ⚠️  '+m, S.warn, ...a);
  const err  = (m, ...a) => console.error(T+' ❌ '+m, S.err,  ...a);

  log('Starting MWA injection — wallet-standard-mobile@%s (inline bundle)', VERSION);

  // ── Result object ──────────────────────────────────────────────────────────
  const result = {
    version:         VERSION,
    timestamp:       new Date().toISOString(),
    isAndroid:       false,
    isSecureContext: false,
    moduleLoaded:    false,
    registered:      false,
    walletType:      null,
    error:           null,
  };

  // ── Guard: already injected ────────────────────────────────────────────────
  if (window.__mwa?.registered) {
    warn('Already injected. Delete window.__mwa to re-run.');
    return window.__mwa;
  }

  // ── STEP 1: Environment checks ─────────────────────────────────────────────
  result.isAndroid       = /android/i.test(navigator.userAgent);
  result.isSecureContext = window.isSecureContext;

  if (result.isAndroid) {
    ok('Android confirmed: %s', navigator.userAgent.match(/Android [\d.]+/)?.[0] ?? 'Android');
  } else {
    warn('Non-Android — will register remote (QR) wallet instead.');
  }

  if (!result.isSecureContext) {
    err('Page is NOT a secure context (HTTPS required). registerMwa() will abort.');
    result.error = 'Not a secure context';
    window.__mwa = result;
    return result;
  }
  ok('Secure context confirmed (HTTPS)');

  // ── STEP 2: Decode inline bundle → Blob URL ────────────────────────────────
  // The bundle is stored as base64 below. We decode it to a Blob, then create
  // an object:// URL. This sidesteps all CSP script-src restrictions because
  // the data never leaves the page — no external network request is made.
  log('Decoding inline bundle...');

  let blobUrl;
  try {
    // Inline base64 of @solana-mobile/wallet-standard-mobile@0.4.4 (esbuild ESM)
    const BUNDLE_B64 = '';

    // atob → Uint8Array → Blob → object URL
    const raw      = atob(BUNDLE_B64);
    const bytes    = new Uint8Array(raw.length);
    for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
    const blob     = new Blob([bytes], { type: 'application/javascript' });
    blobUrl        = URL.createObjectURL(blob);
    ok('Blob URL created: %s', blobUrl.slice(0, 40) + '...');
  } catch (e) {
    result.error = `Blob creation failed: ${e.message}`;
    err('Failed to create Blob URL: %s', e.message);
    window.__mwa = result;
    return result;
  }

  // ── STEP 3: Import from Blob URL ───────────────────────────────────────────
  let mod;
  try {
    mod = await import(blobUrl);
    URL.revokeObjectURL(blobUrl);   // free memory
    result.moduleLoaded = true;
    ok('Module loaded. Exports: %s', Object.keys(mod).join(', '));
  } catch (e) {
    URL.revokeObjectURL(blobUrl);
    result.error = `Module import failed: ${e.message}`;
    err('import() from Blob URL failed: %s', e.message);
    window.__mwa = result;
    return result;
  }

  // ── STEP 4: Destructure exports ────────────────────────────────────────────
  const {
    registerMwa,
    createDefaultAuthorizationCache,
    createDefaultChainSelector,
    createDefaultWalletNotFoundHandler,
  } = mod;

  if (typeof registerMwa !== 'function') {
    result.error = `registerMwa not found. Got: ${Object.keys(mod).join(', ')}`;
    err('registerMwa() missing from bundle exports');
    window.__mwa = result;
    return result;
  }
  ok('registerMwa() confirmed');

  // ── STEP 5: Build config and call registerMwa() ───────────────────────────
  const CHAINS = [
    'solana:mainnet',
    'solana:devnet',
    'solana:testnet',
    'solana:localnet',
  ];

  const config = {
    appIdentity: {
      name: 'SMWA Injection Tool',
      uri:  window.location.origin,
      icon: 'favicon.ico',
    },
    authorizationCache:  createDefaultAuthorizationCache(),
    chains:              CHAINS,
    chainSelector:       createDefaultChainSelector(),
    onWalletNotFound:    createDefaultWalletNotFoundHandler(),
    remoteHostAuthority: undefined,
  };

  log('Calling registerMwa()...');
  log('App identity: "%s" @ %s', config.appIdentity.name, config.appIdentity.uri);
  log('Chains: %s', CHAINS.join(', '));

  try {
    registerMwa(config);
    result.registered = true;

    const ua        = navigator.userAgent;
    const isWebView = /(WebView|; wv\))/i.test(ua);
    const isAndroid = /android/i.test(ua);
    const isDesktop = !/android|iphone|ipad/i.test(ua);

    if (isAndroid && !isWebView) {
      result.walletType = 'LocalSolanaMobileWalletAdapterWallet';
      ok('Wallet type: Local (Android direct connection)');
    } else if (isDesktop) {
      result.walletType = 'RemoteSolanaMobileWalletAdapterWallet';
      warn('Wallet type: Remote (desktop QR mode — needs relay server for full flow)');
    } else {
      result.walletType = 'Skipped — WebView or unsupported context';
      warn('registerMwa() likely skipped registration (WebView detected)');
    }

  } catch (e) {
    result.error = `registerMwa() threw: ${e.message}`;
    err('registerMwa() failed: %s', e.message);
    window.__mwa = result;
    return result;
  }

  // ── STEP 6: Fire compat event for legacy dApp listeners ───────────────────
  try {
    window.dispatchEvent(new Event('wallet-standard:register-wallet'));
    log('Fired wallet-standard:register-wallet compat event');
  } catch (_) {}

  // ── STEP 7: Summary ────────────────────────────────────────────────────────
  window.__mwa = result;

  console.groupCollapsed('%c[MWA-INJECT] Result — click to expand', S.ok);
  console.table({
    'Package':       result.version,
    'Timestamp':     result.timestamp,
    'Android':       result.isAndroid      ? '✅ yes' : '⚠️  no',
    'Secure ctx':    result.isSecureContext ? '✅ yes' : '❌ no',
    'Module loaded': result.moduleLoaded   ? '✅ yes' : '❌ no',
    'Registered':    result.registered     ? '✅ yes' : '❌ no',
    'Wallet type':   result.walletType     ?? 'N/A',
    'Error':         result.error          ?? 'none',
  });
  console.groupEnd();

  if (result.registered) {
    ok('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    ok('MWA wallet injected successfully!');
    ok('Open the dApp wallet picker → look for "Mobile Wallet Adapter"');
    ok('Full result at: window.__mwa');
    ok('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  } else {
    err('Injection failed. Check window.__mwa.error for details.');
  }

  return result;

})();
